"use strict";(self.webpackChunksentinel_docs=self.webpackChunksentinel_docs||[]).push([[2576],{13050:e=>{e.exports=JSON.parse('{"version":{"pluginId":"sdk","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/sdk/","label":"\ud83d\udcd8 Overview","docId":"README","unlisted":false},{"type":"category","label":"\u2699\ufe0f Official SDKs","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/sdk/golang","label":"\ud83d\udd27 Golang","docId":"official-sdks/golang","unlisted":false},{"type":"link","href":"/sdk/javascript","label":"\ud83d\udce6 Javascript","docId":"official-sdks/javascript","unlisted":false},{"type":"link","href":"/sdk/python","label":"\ud83d\udc0d Python","docId":"official-sdks/python","unlisted":false}]},{"type":"category","label":"\ud83c\udf10 Community SDKs","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/sdk/dotnet","label":"\ud83d\udfe6 .NET / C#","docId":"community-sdks/dotnet","unlisted":false},{"type":"link","href":"/sdk/blue-js","label":"\ud83d\udfe6 Blue JavaScript","docId":"community-sdks/blue-js","unlisted":false}]},{"type":"category","label":"\ud83e\udd16 Agent & Automation","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/sdk/ai-connect","label":"\ud83e\udd16 AI Connect","docId":"agent-automation/ai-connect","unlisted":false},{"type":"link","href":"/sdk/x402","label":"\ud83d\udcb3 x402","docId":"agent-automation/x402","unlisted":false},{"type":"link","href":"/sdk/plan-manager","label":"\ud83d\udccb Plan Manager","docId":"agent-automation/plan-manager","unlisted":false}]}]},"docs":{"agent-automation/ai-connect":{"id":"agent-automation/ai-connect","title":"AI Connect","description":"Sentinel AI Connect (blue-agent-connect) is a community-maintained JavaScript library that gives AI agents one-call decentralized VPN connectivity. Zero accounts, zero servers, zero centralized dependencies. One function call to an encrypted P2P tunnel - no API keys, no terms of service, no human approval required. It is built on top of the Blue JavaScript SDK.","sidebar":"tutorialSidebar"},"agent-automation/plan-manager":{"id":"agent-automation/plan-manager","title":"Plan Manager","description":"Sentinel Plan Manager is a community-built commerce layer for the Sentinel decentralized VPN. It is a full-stack web studio for creating on-chain subscription plans, curating node pools, managing subscribers, and issuing fee grants - turning the raw Sentinel protocol into a revenue-generating bandwidth business that anyone can run from a laptop. It is built on top of the Blue JavaScript SDK.","sidebar":"tutorialSidebar"},"agent-automation/x402":{"id":"agent-automation/x402","title":"x402","description":"x402 is a community-built payments layer that lets AI agents pay USDC on Base or Solana for private VPN access through the Sentinel dVPN network of 900+ decentralized nodes. One function call: no KYC, no accounts, no P2P tokens. The agent pays USDC, connects to a VPN, and is private.","sidebar":"tutorialSidebar"},"community-sdks/blue-js":{"id":"community-sdks/blue-js","title":"Blue JavaScript","description":"Blue JS SDK is a community-maintained JavaScript/TypeScript SDK for the Sentinel decentralized VPN network. It supports WireGuard and V2Ray tunnels, talks to the Cosmos blockchain, and works against the live network of 900+ nodes. Queries are RPC-based, events are typed, and the package is CosmJS compatible.","sidebar":"tutorialSidebar"},"community-sdks/dotnet":{"id":"community-sdks/dotnet","title":".NET / C#","description":"SDK","sidebar":"tutorialSidebar"},"official-sdks/golang":{"id":"official-sdks/golang","title":"Golang","description":"The Go SDK is the most complete of the three - it covers the full stack from blockchain client operations down to native VPN tunnel management. Built on Cosmos SDK and CometBFT, it provides everything needed to query chain state, sign transactions, communicate with nodes, and run WireGuard, V2Ray, or OpenVPN tunnels. This is the SDK used by node operators and service builders.","sidebar":"tutorialSidebar"},"official-sdks/javascript":{"id":"official-sdks/javascript","title":"Javascript","description":"The JavaScript SDK lets you interact with the Sentinel blockchain from any browser or Node.js environment. It extends CosmJS, the standard JavaScript library for Cosmos chains - adding Sentinel-specific queries, transactions, and VPN session management on top. If you\'ve worked with CosmJS before, you\'ll feel right at home.","sidebar":"tutorialSidebar"},"official-sdks/python":{"id":"official-sdks/python","title":"Python","description":"The Python SDK provides a straightforward way to query the Sentinel blockchain, manage subscriptions, and handle VPN sessions from Python. It talks to the chain over gRPC using sentinel-protobuf for message definitions and mospy for transaction signing. It\'s a good fit for scripting, automation, and building backend services that need to interact with Sentinel nodes.","sidebar":"tutorialSidebar"},"README":{"id":"README","title":"Overview","description":"Sentinel ships official SDKs for Go, JavaScript, and Python - each covering a different language and use case, but all letting you query chain state, manage subscriptions and sessions, and connect to dVPN nodes. The community has also built additional SDKs and libraries that extend support to other languages and use cases; those are listed under Community SDKs below and are not officially maintained by the Sentinel team.","sidebar":"tutorialSidebar"}}}}')}}]);